   104→
   105→pub const SYSTEM_OUTPUT_TAGS: &[&str] = &[
   106→    LOCAL_COMMAND_STDERR_TAG,
   107→    LOCAL_COMMAND_STDOUT_TAG,
   108→    "<local-command-caveat>",
   109→    "<system-reminder>",
   110→    BASH_STDOUT_TAG,
   111→    BASH_STDERR_TAG,
   112→    TASK_NOTIFICATION_TAG,
   113→];
   114→
   115→const NOISE_ENTRY_TYPES: &[&str] = &[
   116→    "system",
   117→    "file-history-snapshot",
   118→    "queue-operation",
   119→    "progress",
   120→];
   121→
   122→const HARD_NOISE_TAGS: &[&str] = &["<local-command-caveat>", "<system-reminder>"];
   123→
   124→const EMPTY_STDOUT: &str = "<local-command-stdout></local-command-stdout>";
   125→const EMPTY_STDERR: &str = "<local-command-stderr></local-command-stderr>";
   126→
   127→/// Parse an ISO 8601 timestamp. Returns epoch on failure.
   128→pub fn parse_timestamp(s: &str) -> DateTime<Utc> {
   129→    if let Ok(dt) = DateTime::parse_from_rfc3339(s) {
   130→        return dt.with_timezone(&Utc);
   131→    }
   132→    // Try without timezone
   133→    if let Ok(naive) = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S%.f") {
   134→        return Utc.from_utc_datetime(&naive);
   135→    }
   136→    Utc::now() // fallback; ideally epoch but using now for simplicity
   137→}
   138→
   139→/// Classify maps a raw Entry to a ClassifiedMsg. Returns None for noise.
   140→pub fn classify(e: Entry) -> Option<ClassifiedMsg> {
   141→    if e.is_sidechain {
   142→        return None;
   143→    }
   144→
   145→    let ts = parse_timestamp(&e.timestamp);
   146→
   147→    // Rescue hook_progress from noise filter before discarding all "progress" entries.
   148→    if e.entry_type == "progress" {
   149→        if let Some(ref data) = e.data {
   150→            if data.get("type").and_then(|v| v.as_str()) == Some("hook_progress") {
   151→                let hook_event = data
   152→                    .get("hookEvent")
   153→                    .and_then(|v| v.as_str())
   154→                    .unwrap_or("")
   155→                    .to_string();
   156→                let hook_name = data
   157→                    .get("hookName")
   158→                    .and_then(|v| v.as_str())
   159→                    .unwrap_or("")
   160→                    .to_string();
   161→                let command = data
   162→                    .get("command")
   163→                    .and_then(|v| v.as_str())
   164→                    .unwrap_or("")
   165→                    .to_string();
   166→                return Some(ClassifiedMsg::Hook(HookMsg {
   167→                    timestamp: ts,
   168→                    hook_event,
   169→                    hook_name,
   170→                    command,
   171→                }));
   172→            }
   173→        }
   174→    }
   175→
   176→    // Hard noise: structural metadata types.
   177→    if NOISE_ENTRY_TYPES.contains(&e.entry_type.as_str()) {
   178→        return None;
   179→    }
   180→
   181→    // Summary entries -> CompactMsg.
   182→    if e.entry_type == "summary" {
   183→        return Some(ClassifiedMsg::Compact(CompactMsg {
   184→            timestamp: ts,
   185→            text: e.summary.clone(),
   186→        }));
   187→    }
   188→
   189→    // Synthetic assistant messages.
   190→    if e.entry_type == "assistant" && e.message.model == "<synthetic>" {
   191→        return None;
   192→    }
   193→
   194→    let content_str = extract_text(&e.message.content);
   195→
   196→    // Filter user-type noise.
   197→    if e.entry_type == "user" && is_user_noise(&e.message.content, &content_str) {
   198→        return None;
   199→    }
   200→
   201→    // Teammate messages.
   202→    if e.entry_type == "user" {
   203→        let trimmed = content_str.trim();
   204→        if TEAMMATE_MESSAGE_RE.is_match(trimmed) {
   205→            let inner = extract_teammate_content(trimmed);
   206→            if TEAMMATE_PROTOCOL_RE.is_match(&inner) {
   207→                return None;
   208→            }
   209→            let teammate_id = extract_teammate_id(trimmed);
   210→            let color = extract_teammate_color(trimmed);
   211→            let text = sanitize_content(&inner);
   212→            return Some(ClassifiedMsg::Teammate(TeammateMsg {
   213→                timestamp: ts,
   214→                text,
   215→                teammate_id,
   216→                color,
   217→            }));
   218→        }
   219→    }
   220→
   221→    // System message: user entry starting with command output tag.
   222→    if e.entry_type == "user" {
   223→        let trimmed = content_str.trim();
   224→        if trimmed.starts_with(LOCAL_COMMAND_STDOUT_TAG)
   225→            || trimmed.starts_with(LOCAL_COMMAND_STDERR_TAG)
   226→        {
   227→            return Some(ClassifiedMsg::System(SystemMsg {
   228→                timestamp: ts,
   229→                output: extract_command_output(&content_str),
   230→                is_error: false,
   231→            }));
   232→        }
   233→        if trimmed.starts_with(BASH_STDOUT_TAG) || trimmed.starts_with(BASH_STDERR_TAG) {
   234→            let stderr_content = RE_BASH_STDERR
   235→                .captures(&content_str)
   236→                .and_then(|c| c.get(1))
   237→                .map(|m| m.as_str().trim().to_string())
   238→                .unwrap_or_default();
   239→            return Some(ClassifiedMsg::System(SystemMsg {
   240→                timestamp: ts,
   241→                output: extract_bash_output(&content_str),
   242→                is_error: !stderr_content.is_empty(),
   243→            }));
   244→        }
   245→        if trimmed.starts_with(TASK_NOTIFICATION_TAG) {
   246→            let status = RE_TASK_NOTIFY_STATUS
   247→                .captures(&content_str)
   248→                .and_then(|c| c.get(1))
   249→                .map(|m| m.as_str().trim().to_string())
   250→                .unwrap_or_default();
   251→            return Some(ClassifiedMsg::System(SystemMsg {
   252→                timestamp: ts,
   253→                output: extract_task_notification(&content_str),
   254→                is_error: status == "failed",
   255→            }));
   256→        }
   257→    }
   258→
   259→    // ToolSearch results.
   260→    if e.entry_type == "user" && content_str.trim() == "Tool loaded." {
   261→        if let Some(names) = extract_tool_search_matches(&e.tool_use_result) {
   262→            if !names.is_empty() {
   263→                return Some(ClassifiedMsg::System(SystemMsg {
   264→                    timestamp: ts,
   265→                    output: format!("Loaded: {}", names.join(", ")),
   266→                    is_error: false,
   267→                }));
   268→            }
   269→        }
   270→    }
   271→
   272→    // User message.
   273→    if e.entry_type == "user" && !e.is_meta {
   274→        let trimmed = content_str.trim();
   275→        let excluded = SYSTEM_OUTPUT_TAGS
   276→            .iter()
   277→            .any(|tag| trimmed.starts_with(tag));
   278→        if !excluded && has_user_content(&e.message.content, &content_str) {
   279→            return Some(ClassifiedMsg::User(UserMsg {
   280→                timestamp: ts,
   281→                text: sanitize_content(&content_str),
   282→                permission_mode: e.permission_mode.clone(),
   283→            }));
   284→        }
   285→    }
   286→
   287→    // AI message (assistant).
   288→    if e.entry_type == "assistant" {
   289→        let (thinking, tool_calls, blocks) = extract_assistant_details(&e.message.content);
   290→        let stop_reason = e.message.stop_reason.clone().unwrap_or_default();
   291→        return Some(ClassifiedMsg::AI(AIMsg {
   292→            timestamp: ts,
   293→            model: e.message.model.clone(),
   294→            text: sanitize_content(&extract_text(&e.message.content)),
   295→            thinking_count: thinking,
   296→            tool_calls,
   297→            blocks,
   298→            usage: Usage {
   299→                input_tokens: e.message.usage.input_tokens,
   300→                output_tokens: e.message.usage.output_tokens,
   301→                cache_read_tokens: e.message.usage.cache_read_input_tokens,
   302→                cache_creation_tokens: e.message.usage.cache_creation_input_tokens,
   303→            },
   304→            stop_reason,
   305→            is_meta: false,
   306→        }));
   307→    }
   308→
   309→    // Fallback: remaining user messages -> AI message (meta).
   310→    let blocks = extract_meta_blocks(&e.message.content, &content_str);
   311→    Some(ClassifiedMsg::AI(AIMsg {
   312→        timestamp: ts,
   313→        model: String::new(),
   314→        text: content_str,
   315→        thinking_count: 0,
   316→        tool_calls: Vec::new(),
   317→        blocks,
   318→        usage: Usage::default(),
   319→        stop_reason: String::new(),
   320→        is_meta: true,
   321→    }))
   322→}
   323→
   324→fn extract_teammate_id(s: &str) -> String {
   325→    TEAMMATE_ID_RE
   326→        .captures(s)
   327→        .and_then(|c| c.get(1))
   328→        .map(|m| m.as_str().to_string())
   329→        .unwrap_or_default()
   330→}
   331→
   332→fn extract_teammate_color(s: &str) -> String {
   333→    TEAMMATE_COLOR_RE
   334→        .captures(s)
   335→        .and_then(|c| c.get(1))
   336→        .map(|m| m.as_str().to_string())
   337→        .unwrap_or_default()
   338→}
   339→
   340→fn extract_teammate_content(s: &str) -> String {
   341→    TEAMMATE_CONTENT_RE
   342→        .captures(s)
   343→        .and_then(|c| c.get(1))
   344→        .map(|m| m.as_str().trim().to_string())
   345→        .unwrap_or_else(|| s.to_string())
   346→}
   347→
   348→fn is_user_noise(raw: &Option<Value>, content_str: &str) -> bool {
   349→    let trimmed = content_str.trim();
   350→
   351→    for tag in HARD_NOISE_TAGS {
   352→        let close_tag = tag.replace('<', "</");
   353→        if trimmed.starts_with(tag) && trimmed.ends_with(&close_tag) {
   354→            return true;
   355→        }
   356→    }
   357→
   358→    if trimmed == EMPTY_STDOUT || trimmed == EMPTY_STDERR {
   359→        return true;
   360→    }
   361→
   362→    if trimmed.starts_with("[Request interrupted by user") {
   363→        return true;
   364→    }
   365→
   366→    // Check array interruption
   367→    if let Some(Value::Array(blocks)) = raw {
   368→        if blocks.len() == 1 {
   369→            if let Some(block) = blocks.first() {
   370→                let bt = block.get("type").and_then(|v| v.as_str()).unwrap_or("");
   371→                let text = block.get("text").and_then(|v| v.as_str()).unwrap_or("");
   372→                if bt == "text" && text.starts_with("[Request interrupted by user") {
   373→                    return true;
   374→                }
   375→            }
   376→        }
   377→    }
   378→    false
   379→}
   380→
   381→fn has_user_content(raw: &Option<Value>, str_content: &str) -> bool {
   382→    match raw {
   383→        Some(Value::String(_)) => !str_content.trim().is_empty(),
   384→        Some(Value::Array(blocks)) => blocks.iter().any(|b| {
   385→            let bt = b.get("type").and_then(|v| v.as_str()).unwrap_or("");
   386→            bt == "text" || bt == "image"
   387→        }),
   388→        _ => false,
   389→    }
   390→}
   391→
   392→fn extract_tool_search_matches(raw: &Option<Value>) -> Option<Vec<String>> {
   393→    let val = raw.as_ref()?;
   394→    let matches = val.get("matches")?;
   395→    let arr = matches.as_array()?;
   396→    let names: Vec<String> = arr
   397→        .iter()
   398→        .filter_map(|v| v.as_str().map(|s| s.to_string()))
   399→        .collect();
   400→    if names.is_empty() {
   401→        None
   402→    } else {
   403→        Some(names)
   404→    }
   405→}
   406→
   407→fn extract_assistant_details(content: &Option<Value>) -> (usize, Vec<ToolCall>, Vec<ContentBlock>) {
   408→    let blocks = match content {
   409→        Some(Value::Array(arr)) => arr,
   410→        _ => return (0, Vec::new(), Vec::new()),
   411→    };
   412→
   413→    let mut thinking = 0;
   414→    let mut calls = Vec::new();
   415→    let mut content_blocks = Vec::new();
   416→
   417→    for b in blocks {
   418→        let bt = b.get("type").and_then(|v| v.as_str()).unwrap_or("");
   419→        match bt {
   420→            "thinking" => {
   421→                thinking += 1;
   422→                content_blocks.push(ContentBlock {
   423→                    block_type: "thinking".to_string(),
   424→                    text: b
   425→                        .get("thinking")
   426→                        .and_then(|v| v.as_str())
   427→                        .unwrap_or("")
   428→                        .to_string(),
   429→                    ..Default::default()
   430→                });
   431→            }
   432→            "text" => {
   433→                content_blocks.push(ContentBlock {
   434→                    block_type: "text".to_string(),
   435→                    text: b
   436→                        .get("text")
   437→                        .and_then(|v| v.as_str())
   438→                        .unwrap_or("")
   439→                        .to_string(),
   440→                    ..Default::default()
   441→                });
   442→            }
   443→            "tool_use" => {
   444→                let id = b
   445→                    .get("id")
   446→                    .and_then(|v| v.as_str())
   447→                    .unwrap_or("")
   448→                    .to_string();
   449→                let name = b
   450→                    .get("name")
   451→                    .and_then(|v| v.as_str())
   452→                    .unwrap_or("")
   453→                    .to_string();
   454→                if !id.is_empty() && !name.is_empty() {
   455→                    calls.push(ToolCall {
   456→                        id: id.clone(),
   457→                        name: name.clone(),
   458→                    });
   459→                }
   460→                content_blocks.push(ContentBlock {
   461→                    block_type: "tool_use".to_string(),
   462→                    tool_id: id,
   463→                    tool_name: name,
   464→                    tool_input: b.get("input").cloned(),
   465→                    ..Default::default()
   466→                });
   467→            }
   468→            _ => {
   469→                content_blocks.push(ContentBlock {
   470→                    block_type: bt.to_string(),
   471→                    text: b
   472→                        .get("text")
   473→                        .and_then(|v| v.as_str())
   474→                        .unwrap_or("")
   475→                        .to_string(),
   476→                    ..Default::default()
   477→                });
   478→            }
   479→        }
   480→    }
   481→
   482→    (thinking, calls, content_blocks)
   483→}
   484→
   485→fn extract_meta_blocks(content: &Option<Value>, text_fallback: &str) -> Vec<ContentBlock> {
   486→    let blocks = match content {
   487→        Some(Value::Array(arr)) => arr,
   488→        _ => {
   489→            return vec![ContentBlock {
   490→                block_type: "text".to_string(),
   491→                text: text_fallback.to_string(),
   492→                ..Default::default()
   493→            }];
   494→        }
   495→    };
   496→
   497→    let has_tool_result = blocks
   498→        .iter()
   499→        .any(|b| b.get("type").and_then(|v| v.as_str()) == Some("tool_result"));
   500→
   501→    if !has_tool_result {
   502→        return vec![ContentBlock {
   503→            block_type: "text".to_string(),
   504→            text: text_fallback.to_string(),
   505→            ..Default::default()
   506→        }];
   507→    }
   508→
   509→    blocks
   510→        .iter()
   511→        .filter_map(|b| {
   512→            let bt = b.get("type").and_then(|v| v.as_str())?;
   513→            if bt != "tool_result" {
   514→                return None;
   515→            }
   516→            let tool_id = b
   517→                .get("tool_use_id")
   518→                .and_then(|v| v.as_str())
   519→                .unwrap_or("")
   520→                .to_string();
   521→            let raw_content = stringify_content(&b.get("content").cloned());
   522→            let content = resolve_persisted_output(&raw_content);
   523→            let is_error = b.get("is_error").and_then(|v| v.as_bool()).unwrap_or(false);
   524→            Some(ContentBlock {
   525→                block_type: "tool_result".to_string(),
   526→                tool_id,
   527→                content,
   528→                is_error,
   529→                ..Default::default()
   530→            })
   531→        })
   532→        .collect()
   533→}
